    public function testSkipLeadingUnderscoreDisabledIncludesUnderscoreMethods(): void
    {
        $api = new \voku\PhpReadmeHelper\GenerateApi();
        $api->skipMethodsWithLeadingUnderscore = false;

        $result = $api->generate(
