    public function testNativeTypedPropertyUsesNativeTypeWhenNoPhpDoc(): void
    {
        $api = new \voku\PhpReadmeHelper\GenerateApi();

        $result = $api->generate(
            __DIR__ . '/',
            __DIR__ . '/fixtures/base_extended_with_properties.md',
